/**
 * Analytics repository — data access helpers for analytics aggregation.
 *
 * Unlike other repositories, AnalyticsRepository does NOT extend BaseRepository
 * because it doesn't manage its own collection. Instead, it reads from the
 * 'orders' and 'users' collections and provides aggregation-oriented queries.
 *
 * This separation keeps aggregation logic out of OrderRepository/UserRepository
 * while still going through the Database layer (respecting the repo pattern).
 */

import type { Database, DatabaseRecord } from '../utils/database.js';
import type { Order, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsRepository {
  private logger = new Logger('Repository:analytics');

  constructor(private db: Database) {}

  /**
   * Find all orders within a date range (inclusive on both ends).
   */
  findOrdersInRange(startDate: Date, endDate: Date): Order[] {
    this.logger.debug(
      `Finding orders in range: ${startDate.toISOString()} – ${endDate.toISOString()}`,
    );
    const records = this.db.findAll('orders');
    return records
      .map((r) => this.toOrder(r))
      .filter((o) => o.createdAt >= startDate && o.createdAt <= endDate);
  }

  /**
   * Find all users created within a date range (inclusive on both ends).
   */
  findUsersCreatedInRange(startDate: Date, endDate: Date): User[] {
    this.logger.debug(
      `Finding users created in range: ${startDate.toISOString()} – ${endDate.toISOString()}`,
    );
    const records = this.db.findAll('users');
    return records
      .map((r) => this.toUser(r))
      .filter((u) => u.createdAt >= startDate && u.createdAt <= endDate);
  }

  /**
   * Count orders grouped by status within an optional date range.
   */
  countOrdersByStatus(startDate?: Date, endDate?: Date): Record<OrderStatus, number> {
    const orders = startDate && endDate
      ? this.findOrdersInRange(startDate, endDate)
      : this.db.findAll('orders').map((r) => this.toOrder(r));

    const counts: Record<OrderStatus, number> = {
      pending: 0,
      confirmed: 0,
      shipped: 0,
      delivered: 0,
      cancelled: 0,
    };
    for (const order of orders) {
      if (order.status in counts) {
        counts[order.status]++;
      }
    }
    return counts;
  }

  /**
   * Sum total revenue for orders grouped by status within an optional date range.
   */
  sumRevenueByStatus(startDate?: Date, endDate?: Date): Record<OrderStatus, number> {
    const orders = startDate && endDate
      ? this.findOrdersInRange(startDate, endDate)
      : this.db.findAll('orders').map((r) => this.toOrder(r));

    const revenue: Record<OrderStatus, number> = {
      pending: 0,
      confirmed: 0,
      shipped: 0,
      delivered: 0,
      cancelled: 0,
    };
    for (const order of orders) {
      if (order.status in revenue) {
        revenue[order.status] += order.total;
      }
    }
    return revenue;
  }

  // ── Record → Domain mappers ─────────────────────────────────────

  private toOrder(record: DatabaseRecord): Order {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      items: (record['items'] ?? []) as Order['items'],
      total: record['total'] as number,
      status: record['status'] as OrderStatus,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  private toUser(record: DatabaseRecord): User {
    return {
      id: record['id'] as string,
      name: record['name'] as string,
      email: record['email'] as string,
      role: record['role'] as User['role'],
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }
}

/**
 * Analytics service — business logic for dashboard analytics.
 *
 * Depends on AnalyticsRepository for date-range queries and aggregation helpers.
 *
 * Architecture notes:
 * - All methods accept an AnalyticsQuery to define the time window.
 * - Aggregation is computed on-the-fly from order/user data.
 * - Each public method maps to one analytics API operation.
 *
 * Intended API surface (when an HTTP layer is added):
 *   GET /api/analytics/dashboard       → getDashboard()
 *   GET /api/analytics/metrics/:type   → getMetric()
 *   GET /api/analytics/top-products    → getTopProducts()
 */

import type { AnalyticsRepository } from '../repositories/analytics.repository.js';
import type { Order } from '../models/order.js';
import type { OrderStatus } from '../models/order.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeGranularity,
  TimeSeries,
  TimeSeriesPoint,
  TopProduct,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(private analyticsRepository: AnalyticsRepository) {}

  /**
   * Get the full dashboard data for a time range.
   *
   * Combines all metric summaries, order-status breakdown,
   * and key time series into a single response.
   */
  getDashboard(query: AnalyticsQuery): DashboardData {
    this.logger.info(
      `Building dashboard: ${query.startDate.toISOString()} to ${query.endDate.toISOString()} (${query.granularity})`,
    );

    const orders = this.analyticsRepository.findOrdersInRange(query.startDate, query.endDate);
    const users = this.analyticsRepository.findUsersCreatedInRange(query.startDate, query.endDate);

    const ordersByStatus = this.buildOrderStatusBreakdown(orders);
    const revenueOverTime = this.buildTimeSeries('revenue', orders, query.granularity, (bucket) =>
      bucket.reduce((sum, o) => sum + o.total, 0),
    );
    const newUsersOverTime: TimeSeries = {
      metric: 'newUsers',
      points: this.buildTimeSeriesPoints(query.startDate, query.endDate, query.granularity, (start, end) =>
        users.filter((u) => u.createdAt >= start && u.createdAt < end).length,
      ),
    };

    return {
      query,
      metrics: [
        this.getMetric('revenue', query),
        this.getMetric('orders', query),
        this.getMetric('users', query),
        this.getMetric('average-order-value', query),
      ],
      ordersByStatus,
      revenueOverTime,
      newUsersOverTime,
    };
  }

  /**
   * Get a single metric summary with period-over-period comparison.
   *
   * The "previous period" is the same duration immediately before startDate.
   * E.g., if the query spans 7 days, previousValue covers the 7 days before that.
   */
  getMetric(type: MetricType, query: AnalyticsQuery): MetricSummary {
    this.logger.info(`Computing metric: ${type}`);

    const periodMs = query.endDate.getTime() - query.startDate.getTime();
    const prevStart = new Date(query.startDate.getTime() - periodMs);
    const prevEnd = new Date(query.startDate.getTime() - 1);

    const currentOrders = this.analyticsRepository.findOrdersInRange(query.startDate, query.endDate);
    const previousOrders = this.analyticsRepository.findOrdersInRange(prevStart, prevEnd);
    const currentUsers = this.analyticsRepository.findUsersCreatedInRange(query.startDate, query.endDate);
    const previousUsers = this.analyticsRepository.findUsersCreatedInRange(prevStart, prevEnd);

    const currentValue = this.computeMetricValue(type, currentOrders, currentUsers);
    const previousValue = this.computeMetricValue(type, previousOrders, previousUsers);
    const changePercent = previousValue !== 0
      ? ((currentValue - previousValue) / previousValue) * 100
      : 0;

    const timeSeries = this.buildMetricTimeSeries(type, query);

    return {
      type,
      currentValue,
      previousValue,
      changePercent,
      timeSeries,
    };
  }

  /**
   * Get top products by revenue within a time range.
   *
   * @param query - Time range filter
   * @param limit - Max number of products to return (default 10)
   */
  getTopProducts(query: AnalyticsQuery, limit: number = 10): TopProduct[] {
    this.logger.info(`Computing top ${limit} products`);

    const orders = this.analyticsRepository.findOrdersInRange(query.startDate, query.endDate);
    const productMap = new Map<string, { name: string; totalQuantity: number; totalRevenue: number }>();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        if (existing) {
          existing.totalQuantity += item.quantity;
          existing.totalRevenue += item.quantity * item.unitPrice;
        } else {
          productMap.set(item.productId, {
            name: item.name,
            totalQuantity: item.quantity,
            totalRevenue: item.quantity * item.unitPrice,
          });
        }
      }
    }

    return Array.from(productMap.entries())
      .map(([productId, data]) => ({
        productId,
        name: data.name,
        totalQuantity: data.totalQuantity,
        totalRevenue: data.totalRevenue,
      }))
      .sort((a, b) => b.totalRevenue - a.totalRevenue)
      .slice(0, limit);
  }

  // ── Private helpers ────────────────────────────────────────────

  private computeMetricValue(
    type: MetricType,
    orders: Order[],
    users: { id: string }[],
  ): number {
    switch (type) {
      case 'revenue':
        return orders.reduce((sum, o) => sum + o.total, 0);
      case 'orders':
        return orders.length;
      case 'users':
        return users.length;
      case 'average-order-value':
        return orders.length > 0
          ? orders.reduce((sum, o) => sum + o.total, 0) / orders.length
          : 0;
    }
  }

  private buildMetricTimeSeries(type: MetricType, query: AnalyticsQuery): TimeSeries {
    const points = this.buildTimeSeriesPoints(
      query.startDate,
      query.endDate,
      query.granularity,
      (bucketStart, bucketEnd) => {
        const orders = this.analyticsRepository.findOrdersInRange(bucketStart, new Date(bucketEnd.getTime() - 1));
        const users = this.analyticsRepository.findUsersCreatedInRange(bucketStart, new Date(bucketEnd.getTime() - 1));
        return this.computeMetricValue(type, orders, users);
      },
    );

    return { metric: type, points };
  }

  private buildOrderStatusBreakdown(orders: Order[]): OrderStatusBreakdown[] {
    const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
    return statuses.map((status) => {
      const matching = orders.filter((o) => o.status === status);
      return {
        status,
        count: matching.length,
        revenue: matching.reduce((sum, o) => sum + o.total, 0),
      };
    });
  }

  private buildTimeSeries(
    metric: string,
    orders: Order[],
    granularity: TimeGranularity,
    valueFn: (bucket: Order[]) => number,
  ): TimeSeries {
    if (orders.length === 0) {
      return { metric, points: [] };
    }

    const sorted = [...orders].sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime());
    const minDate = sorted[0].createdAt;
    const maxDate = sorted[sorted.length - 1].createdAt;

    const points: TimeSeriesPoint[] = [];
    let bucketStart = this.truncateToGranularity(minDate, granularity);

    while (bucketStart <= maxDate) {
      const bucketEnd = this.advanceByGranularity(bucketStart, granularity);
      const bucketOrders = orders.filter(
        (o) => o.createdAt >= bucketStart && o.createdAt < bucketEnd,
      );
      points.push({
        timestamp: new Date(bucketStart),
        value: valueFn(bucketOrders),
      });
      bucketStart = bucketEnd;
    }

    return { metric, points };
  }

  private buildTimeSeriesPoints(
    startDate: Date,
    endDate: Date,
    granularity: TimeGranularity,
    valueFn: (bucketStart: Date, bucketEnd: Date) => number,
  ): TimeSeriesPoint[] {
    const points: TimeSeriesPoint[] = [];
    let bucketStart = this.truncateToGranularity(startDate, granularity);

    while (bucketStart < endDate) {
      const bucketEnd = this.advanceByGranularity(bucketStart, granularity);
      points.push({
        timestamp: new Date(bucketStart),
        value: valueFn(bucketStart, bucketEnd),
      });
      bucketStart = bucketEnd;
    }

    return points;
  }

  private truncateToGranularity(date: Date, granularity: TimeGranularity): Date {
    const d = new Date(date);
    switch (granularity) {
      case 'hour':
        d.setMinutes(0, 0, 0);
        return d;
      case 'day':
        d.setHours(0, 0, 0, 0);
        return d;
      case 'week': {
        d.setHours(0, 0, 0, 0);
        const day = d.getDay();
        d.setDate(d.getDate() - day);
        return d;
      }
      case 'month':
        d.setHours(0, 0, 0, 0);
        d.setDate(1);
        return d;
    }
  }

  private advanceByGranularity(date: Date, granularity: TimeGranularity): Date {
    const d = new Date(date);
    switch (granularity) {
      case 'hour':
        d.setHours(d.getHours() + 1);
        return d;
      case 'day':
        d.setDate(d.getDate() + 1);
        return d;
      case 'week':
        d.setDate(d.getDate() + 7);
        return d;
      case 'month':
        d.setMonth(d.getMonth() + 1);
        return d;
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { AnalyticsRepository } from '../../src/repositories/analytics.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { DashboardData, MetricSummary } from '../../src/models/analytics.js';

describe('AnalyticsService', () => {
  let db: Database;
  let analyticsRepo: AnalyticsRepository;
  let service: AnalyticsService;

  const defaultQuery = {
    startDate: new Date('2026-01-01'),
    endDate: new Date('2026-01-31'),
    granularity: 'day' as const,
  };

  beforeEach(() => {
    db = new Database();
    analyticsRepo = new AnalyticsRepository(db);
    service = new AnalyticsService(analyticsRepo);
  });

  function insertOrder(overrides: Record<string, unknown> = {}) {
    const id = overrides['id'] as string ?? `order-${Math.random().toString(36).slice(2)}`;
    db.insert('orders', {
      id,
      userId: 'user-1',
      items: [{ productId: 'prod-1', name: 'Widget', quantity: 2, unitPrice: 25 }],
      total: 50,
      status: 'confirmed',
      createdAt: new Date('2026-01-15').toISOString(),
      updatedAt: new Date('2026-01-15').toISOString(),
      ...overrides,
    });
  }

  function insertUser(overrides: Record<string, unknown> = {}) {
    const id = overrides['id'] as string ?? `user-${Math.random().toString(36).slice(2)}`;
    db.insert('users', {
      id,
      name: 'Test User',
      email: `${id}@test.com`,
      role: 'member',
      createdAt: new Date('2026-01-10').toISOString(),
      updatedAt: new Date('2026-01-10').toISOString(),
      ...overrides,
    });
  }

  describe('getDashboard', () => {
    it('should return dashboard data with correct shape', () => {
      const dashboard: DashboardData = service.getDashboard(defaultQuery);

      expect(dashboard.query).toEqual(defaultQuery);
      expect(dashboard.metrics).toHaveLength(4);
      expect(dashboard.ordersByStatus).toHaveLength(5);
      expect(dashboard.revenueOverTime).toBeDefined();
      expect(dashboard.revenueOverTime.metric).toBe('revenue');
      expect(dashboard.newUsersOverTime).toBeDefined();
      expect(dashboard.newUsersOverTime.metric).toBe('newUsers');
    });

    it('should include all four metric types', () => {
      const dashboard = service.getDashboard(defaultQuery);
      const types = dashboard.metrics.map((m) => m.type);

      expect(types).toContain('revenue');
      expect(types).toContain('orders');
      expect(types).toContain('users');
      expect(types).toContain('average-order-value');
    });

    it('should aggregate order data into status breakdown', () => {
      insertOrder({ id: 'o1', status: 'confirmed', total: 100 });
      insertOrder({ id: 'o2', status: 'confirmed', total: 200 });
      insertOrder({ id: 'o3', status: 'pending', total: 50 });

      const dashboard = service.getDashboard(defaultQuery);
      const confirmed = dashboard.ordersByStatus.find((s) => s.status === 'confirmed');
      const pending = dashboard.ordersByStatus.find((s) => s.status === 'pending');

      expect(confirmed?.count).toBe(2);
      expect(confirmed?.revenue).toBe(300);
      expect(pending?.count).toBe(1);
      expect(pending?.revenue).toBe(50);
    });
  });

  describe('getMetric', () => {
    it('should return a metric summary with correct type', () => {
      const metric: MetricSummary = service.getMetric('revenue', defaultQuery);

      expect(metric.type).toBe('revenue');
      expect(metric.timeSeries.metric).toBe('revenue');
      expect(typeof metric.currentValue).toBe('number');
      expect(typeof metric.previousValue).toBe('number');
      expect(typeof metric.changePercent).toBe('number');
    });

    it('should compute revenue from orders in range', () => {
      insertOrder({ id: 'o1', total: 100 });
      insertOrder({ id: 'o2', total: 250 });

      const metric = service.getMetric('revenue', defaultQuery);
      expect(metric.currentValue).toBe(350);
    });

    it('should compute order count', () => {
      insertOrder({ id: 'o1' });
      insertOrder({ id: 'o2' });
      insertOrder({ id: 'o3' });

      const metric = service.getMetric('orders', defaultQuery);
      expect(metric.currentValue).toBe(3);
    });

    it('should compute user count', () => {
      insertUser({ id: 'u1' });
      insertUser({ id: 'u2' });

      const metric = service.getMetric('users', defaultQuery);
      expect(metric.currentValue).toBe(2);
    });

    it('should compute average order value', () => {
      insertOrder({ id: 'o1', total: 100 });
      insertOrder({ id: 'o2', total: 200 });

      const metric = service.getMetric('average-order-value', defaultQuery);
      expect(metric.currentValue).toBe(150);
    });

    it('should handle average-order-value with zero orders', () => {
      const metric = service.getMetric('average-order-value', defaultQuery);
      expect(metric.currentValue).toBe(0);
    });

    it('should compute period-over-period change', () => {
      // Previous period: Dec 2025
      insertOrder({ id: 'o-prev', total: 100, createdAt: new Date('2025-12-15').toISOString() });
      // Current period: Jan 2026
      insertOrder({ id: 'o-curr', total: 150, createdAt: new Date('2026-01-15').toISOString() });

      const metric = service.getMetric('revenue', defaultQuery);
      expect(metric.currentValue).toBe(150);
      expect(metric.previousValue).toBe(100);
      expect(metric.changePercent).toBe(50);
    });

    it('should exclude orders outside the date range', () => {
      insertOrder({ id: 'o-in', total: 100, createdAt: new Date('2026-01-15').toISOString() });
      insertOrder({ id: 'o-out', total: 999, createdAt: new Date('2026-03-01').toISOString() });

      const metric = service.getMetric('revenue', defaultQuery);
      expect(metric.currentValue).toBe(100);
    });
  });

  describe('getTopProducts', () => {
    it('should return an array (empty with no data)', () => {
      const products = service.getTopProducts(defaultQuery, 5);
      expect(Array.isArray(products)).toBe(true);
      expect(products).toHaveLength(0);
    });

    it('should aggregate products across orders', () => {
      insertOrder({
        id: 'o1',
        items: [
          { productId: 'p1', name: 'Widget A', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Widget B', quantity: 1, unitPrice: 50 },
        ],
        total: 70,
      });
      insertOrder({
        id: 'o2',
        items: [
          { productId: 'p1', name: 'Widget A', quantity: 3, unitPrice: 10 },
        ],
        total: 30,
      });

      const products = service.getTopProducts(defaultQuery);
      expect(products).toHaveLength(2);
      expect(products[0].productId).toBe('p2');
      expect(products[0].totalRevenue).toBe(50);
      expect(products[1].productId).toBe('p1');
      expect(products[1].totalQuantity).toBe(5);
      expect(products[1].totalRevenue).toBe(50);
    });

    it('should respect the limit parameter', () => {
      insertOrder({
        id: 'o1',
        items: [
          { productId: 'p1', name: 'A', quantity: 1, unitPrice: 100 },
          { productId: 'p2', name: 'B', quantity: 1, unitPrice: 50 },
          { productId: 'p3', name: 'C', quantity: 1, unitPrice: 25 },
        ],
        total: 175,
      });

      const products = service.getTopProducts(defaultQuery, 2);
      expect(products).toHaveLength(2);
      expect(products[0].totalRevenue).toBe(100);
      expect(products[1].totalRevenue).toBe(50);
    });
  });
});

